results = []
for ref in refs.strip().split('\n'):
    ref = ref.strip().lstrip('/')
    local = f"public/{ref}"
    r = terminal(f"stat --format='%s' /root/elviajero-comercio/{local} 2>/dev/null || echo MISSING", timeout=5)
    size = r['output'].strip()
    ext = ref.split('.')[-1]
    results.append((ref, ext, size))

# Categorize
svgs_ok = []
pngs_good = []  # > 100KB
pngs_small = [] # < 100KB (programmatic, not photorealistic)

for path, ext, size in results:
    if size == 'MISSING':
        print(f"  MISSING: {path}")
    elif ext == 'svg':
        svgs_ok.append(path)
    else:
        try:
            sz = int(size)
            if sz < 50000:
                pngs_small.append((path, sz))
            else:
                pngs_good.append((path, sz))
        except:
            pass

print(f"\n=== SVGs (keep — should be vector) ===")
for p in svgs_ok:
    print(f"  {p}")

print(f"\n=== PNGs > 50KB (photorealistic / real images) ===")
for p, s in pngs_good:
    print(f"  {p} ({s//1024}KB)")

